## Phase 2: Reliability Controls Implementation

```typescript
// infrastructure/circuit-breaker.ts
import { CircuitBreaker } from 'opossum'; // or resilience4j for Java
import { logger } from './observability';

export class PaymentCircuitBreaker {
  private breakers: Map<string, CircuitBreaker>;

  constructor() {
    this.breakers = new Map();
    ['stripe', 'paypal', 'adyen'].forEach(provider => {
      this.breakers.set(provider, new CircuitBreaker(
        async (operation: () => Promise<any>) => operation(),
        {
          timeout: 30000, // 30s
          errorThresholdPercentage: 50,
          resetTimeout: 60000, // 60s
          volumeThreshold: 10,
          name: `payment-${provider}`
        }
      ));

      // Event listeners for observability
      const breaker = this.breakers.get(provider)!;
      breaker.on('open', () => logger.warn(`Circuit opened for ${provider}`));
      breaker.on('halfOpen', () => logger.info(`Circuit half-open for ${provider}`));
      breaker.on('close', () => logger.info(`Circuit closed for ${provider}`));
    });
  }

  async execute<T>(
    provider: string, 
    operation: () => Promise<T>,
    fallback: () => Promise<T>
  ): Promise<T> {
    const breaker = this.breakers.get(provider);
    if (!breaker) throw new Error(`Unknown provider: ${provider}`);

    if (breaker.opened) {
      logger.warn(`Circuit open for ${provider}, using fallback`);
      return fallback();
    }

    return breaker.fire(operation);
  }
}

// infrastructure/rate-limiter.ts
import { RateLimiterRedis } from 'rate-limiter-flexible';

export class CheckoutRateLimiter {
  private userLimiter: RateLimiterRedis;
  private globalLimiter: RateLimiterRedis;

  constructor(redisClient: any) {
    // 100 requests per minute per user
    this.userLimiter = new RateLimiterRedis({
      storeClient: redisClient,
      keyPrefix: 'checkout_user',
      points: 100,
      duration: 60,
    });

    // 1000 requests per minute global
    this.globalLimiter = new RateLimiterRedis({
      storeClient: redisClient,
      keyPrefix: 'checkout_global',
      points: 1000,
      duration: 60,
    });
  }

  async checkLimits(userId: string): Promise<{ allowed: boolean; retryAfter?: number }> {
    try {
      await this.globalLimiter.consume('global', 1);
      await this.userLimiter.consume(userId, 1);
      return { allowed: true };
    } catch (rejRes) {
      return { 
        allowed: false, 
        retryAfter: Math.round(rejRes.msBeforeNext / 1000) || 60 
      };
    }
  }
}
