## Phase 3: Idempotency & State Management

```typescript
// domain/idempotency-service.ts
import { createHash } from 'crypto';
import { Redis } from 'ioredis';

export class IdempotencyService {
  constructor(
    private redis: Redis,
    private db: any // your db client
  ) {}

  async validateAndLock(
    key: string, 
    userId: string, 
    payload: object
  ): Promise<{ valid: boolean; existing?: any; signature: string }> {
    // HMAC validation to prevent tampering
    const signature = createHash('sha256')
      .update(`${key}:${userId}:${JSON.stringify(payload)}`)
      .digest('hex');

    // Check Redis first (fast path)
    const cached = await this.redis.get(`idempotency:${key}`);
    if (cached) {
      const parsed = JSON.parse(cached);
      if (parsed.signature !== signature) {
        throw new Error('Idempotency key mismatch');
      }
      return { valid: false, existing: parsed.response };
    }

    // Check database (source of truth)
    const existing = await this.db.checkoutStates.findUnique({
      where: { idempotencyKey_userId: { idempotencyKey: key, userId } }
    });

    if (existing) {
      // Verify payload integrity
      if (existing.payloadHash !== signature) {
        throw new Error('Idempotency key reuse with different payload');
      }
      return { valid: false, existing };
    }

    return { valid: true, signature };
  }

  async storeResponse(key: string, response: any, signature: string): Promise<void> {
    // Store in Redis with 24h TTL
    await this.redis.setex(
      `idempotency:${key}`,
      86400,
      JSON.stringify({ response, signature, timestamp: Date.now() })
    );
  }
}

// domain/checkout-state-machine.ts
export class CheckoutStateMachine {
  private readonly validTransitions = {
    'PENDING': ['PROCESSING', 'FAILED'],
    'PROCESSING': ['COMPLETED', 'FAILED'],
    'COMPLETED': [],
    'FAILED': ['PENDING'] // Allow retry
  };

  canTransition(from: string, to: string): boolean {
    return this.validTransitions[from]?.includes(to) ?? false;
  }

  async transition(
    db: any,
    checkoutId: string,
    newState: string,
    metadata?: object
  ): Promise<void> {
    const result = await db.$transaction(async (tx: any) => {
      // Optimistic locking
      const current = await tx.checkoutStates.findUnique({
        where: { id: checkoutId },
        select: { status: true, version: true }
      });

      if (!current) throw new Error('Checkout not found');
      if (!this.canTransition(current.status, newState)) {
        throw new Error(`Invalid transition: ${current.status} -> ${newState}`);
      }

      return tx.checkoutStates.update({
        where: { 
          id: checkoutId,
          version: current.version // Ensures no concurrent modification
        },
        data: {
          status: newState,
          version: { increment: 1 },
          ...metadata
        }
      });
    });

    // Emit event for observability
    logger.info(`State transition: ${checkoutId} -> ${newState}`);
    return result;
  }
}
```

