// Distributed Tracing Setup
export const setupTracing = () => {
  const sdk = new NodeSDK({
    traceExporter: new JaegerExporter({ endpoint: 'http://jaeger:14268/api/traces' }),
    metricExporter: new PrometheusExporter({ port: 9090 })
