};

// Metrics
const meter = metrics.getMeter('checkout-api');
export const checkoutMetrics = {
  latency: meter.createHistogram('checkout_latency_ms'),
  errorRate: meter.createCounter('checkout_errors_total'),
  conversionRate: meter.createCounter('checkout_completed_total'),
  revenueAtRisk: meter.createGauge('revenue_at_risk_usd'),
  activeCheckouts: meter.createUpDownCounter('active_checkouts')
};

// Structured Logging
export const logger = winston.createLogger({
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.json()
  ),
  defaultMeta: { service: 'checkout-api' },
  transports: [
    new winston.transports.Console(),
    new winston.transports.File({ filename: 'checkout-error.log', level: 'error' })
  ]
});

// Middleware for request tracing
export const tracingMiddleware = (req: any, res: any, next: any) => {
  const span = trace.getActiveSpan();
  if (span) {
    span.setAttribute('http.route', req.route?.path);
    span.setAttribute('user.id', req.user?.id);
    span.setAttribute('checkout.id', req.headers['x-checkout-id']);
  }

  const startTime = Date.now();
  res.on('finish', () => {
    const duration = Date.now() - startTime;
    checkoutMetrics.latency.record(duration, {
      route: req.route?.path,
      status: res.statusCode
    });

    if (res.statusCode >= 400) {
      checkoutMetrics.errorRate.add(1, { route: req.route?.path });
    }
  });

  next();
};
