// infrastructure/shadow-traffic.ts
export class ShadowTrafficRouter {
  constructor(
    private newApiClient: any,
    private comparator: ResponseComparator
  ) {}

  async mirrorRequest(req: any, res: any, next: any) {
    // Process original request normally
    next();

    // Async mirror to new API (non-blocking)
    if (await shouldMirror()) {
      this.mirrorToNewAPI(req).catch(err => 
        logger.error('Shadow traffic error', { error: err })
      );
    }
  }

  private async mirrorToNewAPI(originalReq: any): Promise<void> {
    const span = trace.getTracer('shadow').startSpan('shadow-request');

    try {
      const startTime = Date.now();
      const shadowResponse = await this.newApiClient.request({
        ...originalReq,
        headers: { ...originalReq.headers, 'x-shadow-mode': 'true' }
      });
      const latency = Date.now() - startTime;

      // Compare responses (async, store diffs)
      const diff = await this.comparator.compare(
        originalReq,
        shadowResponse,
        originalReq.response // captured from actual response
      );

      if (diff.hasDifferences) {
        checkoutMetrics.errorRate.add(1, { type: 'shadow_mismatch' });
        logger.warn('Shadow traffic mismatch', { 
          diff: diff.details,
          endpoint: originalReq.path 
        });
      }

      span.setStatus({ code: SpanStatusCode.OK });
    } catch (error) {
      span.recordException(error);
      span.setStatus({ code: SpanStatusCode.ERROR });
    } finally {
      span.end();
    }
  }
}

