    const body1 = await res1.json();

    // Duplicate request within 5 seconds
    const res2 = await request.post('/api/v2/checkout', {
      headers: { 'Idempotency-Key': idempotencyKey },
      data: payload
    });
    expect(res2.status()).toBe(200);
