  test('concurrent checkout handles inventory race condition', async ({ request }) => {
    const promises = Array(5).fill(null).map(() => 
      request.post('/api/v2/checkout', {
        headers: { 'Idempotency-Key': crypto.randomUUID() },
        data: { cartId: 'limited-item-1', amount: 50 }
      })
    );

    const results = await Promise.all(promises);
    const successes = results.filter(r => r.status() === 200);

    // Only 3 should succeed (inventory limit)
    expect(successes.length).toBeLessThanOrEqual(3);
  });

  test('circuit breaker opens on payment failure', async ({ request }) => {
    // Simulate Stripe failure
    await request.post('/test/simulate-failure', { data: { provider: 'stripe' } });

    // Multiple requests to trigger circuit
    for (let i = 0; i < 15; i++) {
      await request.post('/api/v2/checkout', {
        data: { paymentMethod: 'stripe', amount: 10 }
      });
    }

    // Circuit should be open, fallback to PayPal should work
    const res = await request.post('/api/v2/checkout', {
      data: { paymentMethod: 'stripe', amount: 10, fallback: true }
    });
    expect(res.status()).toBe(200);
  });
});

