## Database Migration Safety

```sql
-- migrations/001_add_idempotency_support.sql
BEGIN;

-- Add idempotency columns without breaking existing API
ALTER TABLE checkout_states 
ADD COLUMN IF NOT EXISTS idempotency_key VARCHAR(255),
ADD COLUMN IF NOT EXISTS payload_hash VARCHAR(64),
ADD COLUMN IF NOT EXISTS version INTEGER DEFAULT 1,
ADD COLUMN IF NOT EXISTS status VARCHAR(20) DEFAULT 'PENDING';

-- Create unique constraint for idempotency
CREATE UNIQUE INDEX IF NOT EXISTS idx_idempotency_user 
ON checkout_states(idempotency_key, user_id) 
WHERE idempotency_key IS NOT NULL;

-- Add state machine constraint
ALTER TABLE checkout_states 
ADD CONSTRAINT valid_status 
CHECK (status IN ('PENDING', 'PROCESSING', 'COMPLETED', 'FAILED'));

COMMIT;
