interface NewCheckout {
  id: string;
  legacy_id?: string;
  cart_data: {
    items: Array<{ sku: string; quantity: number; unit_price: number }>;
    subtotal: number;
  };
  customer_profile: {
    email: string;
    anonymous: boolean;
  };
  amount: number;
  currency: string;
  legacy_mapping: Record<string, unknown>;
}

export class LegacyCompatibilityAdapter {
  private logger = new Logger('LegacyCompat');

  /**
   * Transform legacy format to new schema while preserving original for rollback
   */
  toNewSchema(legacy: LegacyCheckout): NewCheckout {
    const newId = uuidv4();

    return {
      id: newId,
      legacy_id: legacy.orderId,
      cart_data: {
        items: legacy.items.map(item => ({
          sku: item.sku,
          quantity: item.qty,
          unit_price: item.price
        })),
        subtotal: legacy.totalAmount
      },
      customer_profile: {
        email: legacy.customerEmail,
        anonymous: !legacy.customerEmail
      },
      amount: legacy.totalAmount,
      currency: legacy.currency,
      legacy_mapping: { ...legacy } // Full backup for rollback safety
    };
  }

  /**
   * Reverse transform for rollback scenarios
   */
  toLegacySchema(newCheckout: NewCheckout): LegacyCheckout {
    if (!newCheckout.legacy_mapping) {
      throw new Error('Cannot rollback: legacy mapping missing');
    }

    return newCheckout.legacy_mapping as LegacyCheckout;
  }

  /**
   * Dual-write handler: writes to both schemas during transition period
   */
  async dualWrite(
    legacyData: LegacyCheckout,
    writeNew: (data: NewCheckout) => Promise<void>,
    writeLegacy: (data: LegacyCheckout) => Promise<void>
  ): Promise<void> {
    const newData = this.toNewSchema(legacyData);

    try {
      // Write to new schema first (source of truth for new API)
      await writeNew(newData);

      // Write to legacy schema (for backward compatibility)
      await writeLegacy(legacyData);

      this.logger.info('Dual-write successful', {
        newId: newData.id,
        legacyId: legacyData.orderId
      });
    } catch (error) {
      this.logger.error('Dual-write failed', { error, legacyId: legacyData.orderId });
      throw new Error('Checkout data consistency violation');
    }
  }
}
