// agent-core/src/middleware/idempotency.ts
import { Request, Response, NextFunction } from 'express';
import crypto from 'crypto';
import Redis from 'ioredis';
import { logger } from '../utils/logger';

// Initialize Redis client for idempotency key storage
const redis = new Redis(process.env.REDIS_URL || 'redis://localhost:6379');

interface IdempotencyRecord {
  key: string;
  response: any;
  createdAt: number;
  ttl: number;
}

export const idempotencyMiddleware = async (
  req: Request,
  res: Response,
  next: NextFunction
) => {
  // Only apply to POST requests
  if (req.method !== 'POST') {
    return next();
  }

  const idempotencyKey = req.headers['idempotency-key'] as string;

  // Validate idempotency key presence
  if (!idempotencyKey) {
    return res.status(400).json({
      error: 'Missing idempotency-key header'
    });
  }

  // Validate key format (should be UUID or similar)
  if (!/^[a-zA-Z0-9-_]{8,}$/.test(idempotencyKey)) {
    return res.status(400).json({
      error: 'Invalid idempotency key format'
    });
  }

  try {
    // Check if we've seen this key before
    const existingRecord = await redis.get(`idempotency:${idempotencyKey}`);

    if (existingRecord) {
      const record: IdempotencyRecord = JSON.parse(existingRecord);

      // Return cached response
      logger.info('Returning cached response for idempotency key', {
        key: idempotencyKey,
        timestamp: new Date().toISOString()
      });

      return res.status(200).json(record.response);
    }

    // Store request hash to detect duplicate requests with different bodies
    const requestBodyHash = crypto
      .createHash('sha256')
      .update(JSON.stringify(req.body))
      .digest('hex');

    const requestHashKey = `request-hash:${idempotencyKey}`;
    const existingHash = await redis.get(requestHashKey);

    if (existingHash && existingHash !== requestBodyHash) {
      return res.status(409).json({
        error: 'Idempotency key already used with different request body'
      });
    }

    // Store the request hash
    await redis.setex(requestHashKey, 86400, requestBodyHash); // 24 hours TTL

    // Attach idempotency info to request for later use
    (req as any).idempotencyKey = idempotencyKey;
    next();
  } catch (error) {
    logger.error('Error processing idempotency key', {
      error: (error as Error).message,
      key: idempotencyKey
    });

    // Fail open - continue processing but log the error
    (req as any).idempotencyKey = idempotencyKey;
    next();
  }
};

export const storeIdempotencyResponse = async (
  key: string,
  response: any,
  ttl: number = 86400 // Default 24 hours
) => {
  try {
    const record: IdempotencyRecord = {
      key,
      response,
      createdAt: Date.now(),
      ttl
    };

    await redis.setex(
      `idempotency:${key}`,
      ttl,
      JSON.stringify(record)
    );
  } catch (error) {
    logger.error('Failed to store idempotency response', {
      error: (error as Error).message,
      key
    });
  }
};
