import { Request, Response, NextFunction } from 'express';
import Redis from 'ioredis';
import { v4 as uuidv4 } from 'uuid';
import crypto from 'crypto';

interface IdempotencyStore {
  get(key: string): Promise<string | null>;
  set(key: string, value: string, ttl: number): Promise<void>;
  delete(key: string): Promise<void>;
}

export class RedisIdempotencyStore implements IdempotencyStore {
  private redis: Redis;

  constructor(redisUrl: string) {
    this.redis = new Redis(redisUrl, {
      retryStrategy: (times) => Math.min(times * 50, 2000),
      enableReadyCheck: true,
      maxRetriesPerRequest: 3
    });
  }

  async get(key: string): Promise<string | null> {
    return this.redis.get(key);
  }

  async set(key: string, value: string, ttl: number): Promise<void> {
    await this.redis.setex(key, ttl, value);
  }

  async delete(key: string): Promise<void> {
    await this.redis.del(key);
  }
}

interface IdempotencyConfig {
  store: IdempotencyStore;
  ttlSeconds: number;
  keyHeader: string;
}

export const createIdempotencyMiddleware = (config: IdempotencyConfig) => {
  return async (req: Request, res: Response, next: NextFunction) => {
    // Skip for non-mutating methods
    if (!['POST', 'PUT', 'PATCH', 'DELETE'].includes(req.method)) {
      return next();
    }

    const idempotencyKey = req.headers[config.keyHeader.toLowerCase()] as string;

    if (!idempotencyKey) {
      return res.status(400).json({
        error: 'Idempotency-Key header required',
        code: 'MISSING_IDEMPOTENCY_KEY'
      });
    }

    // Validate key format (UUID v4 recommended)
    if (!/^[0-9a-f]{8}-[0-9a-f]{4}-4[0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i.test(idempotencyKey)) {
      return res.status(400).json({
        error: 'Invalid Idempotency-Key format. Expected UUID v4',
        code: 'INVALID_IDEMPOTENCY_KEY'
      });
    }

    const storeKey = `idempotency:${req.method}:${req.path}:${idempotencyKey}`;
    const fingerprint = hashRequest(req);

    try {
      // Check for existing request
      const existing = await config.store.get(storeKey);

      if (existing) {
        const cached = JSON.parse(existing);

        // Verify request fingerprint matches (prevent replay attacks with different payloads)
        if (cached.fingerprint !== fingerprint) {
          return res.status(422).json({
            error: 'Idempotency-Key reused with different payload',
            code: 'IDEMPOTENCY_KEY_REUSE'
          });
        }

        // Return cached response
        return res.status(cached.statusCode)
          .set('Idempotency-Replay', 'true')
          .json(cached.body);
      }

      // Store "in-flight" marker to prevent concurrent processing
      const inFlightKey = `${storeKey}:inflight`;
      const acquired = await config.store.get(inFlightKey);

      if (acquired) {
        return res.status(409).json({
          error: 'Request already in progress',
          code: 'CONCURRENT_REQUEST'
        });
      }

      await config.store.set(inFlightKey, '1', 60); // 60s lock

      // Attach storage functions to response for post-processing
      res.locals.idempotencyKey = storeKey;
      res.locals.idempotencyFingerprint = fingerprint;
      res.locals.idempotencyStore = config.store;

      // Override res.json to cache successful responses
      const originalJson = res.json.bind(res);
      res.json = function(body) {
        if (res.statusCode >= 200 && res.statusCode < 300) {
          const cacheData = {
            statusCode: res.statusCode,
            body,
            fingerprint,
            timestamp: new Date().toISOString()
          };

          // Store result and remove inflight marker
          Promise.all([
            config.store.set(storeKey, JSON.stringify(cacheData), config.ttlSeconds),
            config.store.delete(inFlightKey)
          ]).catch(err => {
            console.error('Failed to cache idempotency response:', err);
          });
        } else {
          // Remove inflight marker on error
          config.store.delete(inFlightKey).catch(console.error);
        }

        return originalJson(body);
      };

      next();
    } catch (error) {
      console.error('Idempotency middleware error:', error);
      // Fail open - allow request to proceed if store is unavailable
      next();
    }
  };
};

function hashRequest(req: Request): string {
  const data = `${req.method}:${req.path}:${JSON.stringify(req.body)}:${req.headers['user-agent']}`;
  return crypto.createHash('sha256').update(data).digest('hex');
}

