import { Request, Response, NextFunction } from 'express';
import Redis from 'ioredis';
import crypto from 'crypto';
import { Logger } from '../../../tools/logging';

const redis = new Redis({
  host: process.env.REDIS_HOST,
  port: parseInt(process.env.REDIS_PORT || '6379'),
  retryStrategy: (times) => Math.min(times * 50, 2000),
  maxRetriesPerRequest: 3
});

const IDEMPOTENCY_TTL = 86400; // 24 hours
const KEY_PREFIX = 'idempotency:checkout:';

interface IdempotencyRecord {
  statusCode: number;
  body: string;
  headers: Record<string, string>;
  createdAt: number;
  userId: string;
  checkoutSessionId: string;
}

export class IdempotencyMiddleware {
  private logger = new Logger('IdempotencyMiddleware');

  /**
   * Validates idempotency key and returns cached response if duplicate
   * Scoped to userId + checkoutSessionId to prevent cross-contamination
   */
  async validate(req: Request, res: Response, next: NextFunction): Promise<void> {
    const idempotencyKey = req.headers['idempotency-key'] as string;

    if (!idempotencyKey) {
      // Generate key for new requests to ensure idempotency on retries
      req.headers['idempotency-key'] = this.generateKey(req);
      return next();
    }

    const userId = req.user?.id;
    const checkoutSessionId = req.body?.checkoutSessionId || req.params?.sessionId;

    if (!userId || !checkoutSessionId) {
      res.status(400).json({ error: 'Missing userId or checkoutSessionId for idempotency scope' });
      return;
    }

    const compositeKey = this.buildCompositeKey(userId, checkoutSessionId, idempotencyKey);
    const fingerprint = this.generateFingerprint(req);

    try {
      const cached = await this.getCachedResponse(compositeKey);

      if (cached) {
        // Verify fingerprint matches to detect key reuse with different payloads
        if (cached.fingerprint && cached.fingerprint !== fingerprint) {
          this.logger.warn('Idempotency key reuse detected with different payload', {
            userId,
            checkoutSessionId,
            key: idempotencyKey
          });
          res.status(409).json({ 
            error: 'Idempotency key already used with different payload',
            code: 'IDEMPOTENCY_KEY_REUSE'
          });
          return;
        }

        // Return cached response within 200ms SLA
        this.logger.info('Idempotency cache hit', { key: idempotencyKey, userId });
        res.status(cached.statusCode)
           .set(cached.headers)
           .send(cached.body);
        return;
      }

      // Store fingerprint for request in progress
      await redis.setex(
        `${compositeKey}:fingerprint`, 
        300, // 5 min lock while processing
        fingerprint
      );

      // Override res.json to capture response for caching
      const originalJson = res.json.bind(res);
      res.json = (body: any) => {
        this.cacheResponse(compositeKey, res.statusCode, body, res.getHeaders() as Record<string, string>, fingerprint)
          .catch(err => this.logger.error('Failed to cache idempotency response', err));
        return originalJson(body);
      };

      next();
    } catch (error) {
      this.logger.error('Idempotency check failed', error);
      // Fail open - allow request to proceed without idempotency guarantee
      next();
    }
  }

  private buildCompositeKey(userId: string, checkoutSessionId: string, key: string): string {
    // Scope prevents cross-user and cross-session contamination
    return `${KEY_PREFIX}${userId}:${checkoutSessionId}:${key}`;
  }

  private generateKey(req: Request): string {
    return crypto.randomUUID();
  }

  private generateFingerprint(req: Request): string {
    // Create hash of method, path, and body to detect payload changes
    const data = `${req.method}:${req.path}:${JSON.stringify(req.body)}`;
    return crypto.createHash('sha256').update(data).digest('hex').substring(0, 16);
  }

  private async getCachedResponse(key: string): Promise<(IdempotencyRecord & { fingerprint?: string }) | null> {
    const data = await redis.get(key);
    if (!data) return null;

    const record: IdempotencyRecord = JSON.parse(data);
    const fingerprint = await redis.get(`${key}:fingerprint`);

    return { ...record, fingerprint: fingerprint || undefined };
  }

  private async cacheResponse(
    key: string, 
    statusCode: number, 
    body: any, 
    headers: Record<string, string>,
    fingerprint: string
  ): Promise<void> {
    const record: IdempotencyRecord = {
      statusCode,
      body: JSON.stringify(body),
      headers: this.sanitizeHeaders(headers),
      createdAt: Date.now(),
      userId: key.split(':')[2],
      checkoutSessionId: key.split(':')[3]
    };

    const pipeline = redis.pipeline();
    pipeline.setex(key, IDEMPOTENCY_TTL, JSON.stringify(record));
    pipeline.setex(`${key}:fingerprint`, IDEMPOTENCY_TTL, fingerprint);
    await pipeline.exec();
  }

  private sanitizeHeaders(headers: Record<string, string>): Record<string, string> {
    // Remove sensitive headers from cached response
    const { 'set-cookie': _, ...safe } = headers;
    return safe;
  }
}

