import { NextFunction, Request, Response } from 'express';
import { logger } from '../utils/logger';

interface RetryConfig {
  maxRetries: number;
  baseDelay: number;
  maxDelay: number;
  exponentialFactor: number;
}

class CircuitBreaker {
  private failureCount: number = 0;
  private lastFailureTime: number = 0;
  private timeout: number;
  private failureThreshold: number;
  private state: 'CLOSED' | 'OPEN' | 'HALF_OPEN' = 'CLOSED';

  constructor(timeout: number = 60000, failureThreshold: number = 5) {
    this.timeout = timeout;
    this.failureThreshold = failureThreshold;
  }

  async call<T>(operation: () => Promise<T>): Promise<T> {
    if (this.state === 'OPEN') {
      if (Date.now() - this.lastFailureTime > this.timeout) {
        this.state = 'HALF_OPEN';
      } else {
        throw new Error('Circuit breaker is OPEN');
      }
    }

    try {
      const result = await operation();
      this.onSuccess();
      return result;
    } catch (error) {
      this.onFailure();
      throw error;
    }
  }

  private onSuccess() {
    this.failureCount = 0;
    this.state = 'CLOSED';
  }

  private onFailure() {
    this.failureCount++;
    this.lastFailureTime = Date.now();

    if (this.failureCount >= this.failureThreshold) {
      this.state = 'OPEN';
    }
  }

  getState() {
    return this.state;
  }
}

const defaultRetryConfig: RetryConfig = {
  maxRetries: 3,
  baseDelay: 1000,
  maxDelay: 10000,
  exponentialFactor: 2
};

export function retryHandler(config: Partial<RetryConfig> = {}) {
  const retryConfig: RetryConfig = { ...defaultRetryConfig, ...config };

  return async function(req: Request, res: Response, next: NextFunction) {
    const circuitBreaker = new CircuitBreaker(60000, 5);

    req.retryOperation = async <T>(
      operation: () => Promise<T>,
      shouldRetry: (error: any) => boolean = () => true
    ): Promise<T> => {
      let lastError: any;

      for (let attempt = 0; attempt <= retryConfig.maxRetries; attempt++) {
        try {
          return await circuitBreaker.call(operation);
        } catch (error) {
          lastError = error;

          // Log retry attempt
          logger.warn(`Retry attempt ${attempt + 1} failed: ${error.message}`, {
            attempt,
            maxRetries: retryConfig.maxRetries,
            endpoint: req.path,
            method: req.method
          });

          // Check if we should retry
          if (attempt === retryConfig.maxRetries || !shouldRetry(error)) {
            break;
          }

          // Calculate delay with exponential backoff
          const delay = Math.min(
            retryConfig.baseDelay * Math.pow(retryConfig.exponentialFactor, attempt),
            retryConfig.maxDelay
          );

          // Add jitter
          const jitter = Math.random() * 0.1 * delay;

          await new Promise(resolve => setTimeout(resolve, delay + jitter));
        }
      }

      throw lastError;
    };

    next();
  };
}

// Add to express request type
declare global {
  namespace Express {
    interface Request {
      retryOperation: <T>(
        operation: () => Promise<T>,
        shouldRetry?: (error: any) => boolean
      ) => Promise<T>;
    }
  }
}
