        if (existing.statusCode) {
          res.status(existing.statusCode);
        }
        res.json(existing.response);
        return;
      }

      // Store pending status
      await redis.set(cacheKey, {
        status: 'pending',
        createdAt: Date.now()
      }, IDEMPOTENCY_CACHE_TTL);

      // Override res.json to cache successful responses
      const originalJson = res.json.bind(res);
      res.json = (body: any) => {
        const statusCode = res.statusCode;

        // Only cache successful responses (2xx)
        if (statusCode >= 200 && statusCode < 300) {
          redis.set(cacheKey, {
            status: 'completed',
            response: body,
            statusCode,
            createdAt: Date.now()
          }, IDEMPOTENCY_CACHE_TTL).catch(err => {
            logger.error('Failed to cache idempotent response', { error: err, idempotencyKey });
          });
        } else if (statusCode >= 400) {
          // Cache failed responses briefly to prevent thundering herd
          redis.set(cacheKey, {
            status: 'failed',
            response: body,
            statusCode,
            createdAt: Date.now()
          }, 60).catch(() => {});
        }

        return originalJson(body);
      };

      next();
    } catch (error) {
      logger.error('Idempotency middleware error', { error, idempotencyKey });
      // Fail open - allow request to proceed if cache is unavailable
      next();
    }
  };
