// agent-core/src/middleware/idempotency.ts
import { Request, Response, NextFunction } from 'express';
import { RedisClientType } from 'redis';
import { v4 as uuidv4 } from 'uuid';

export interface IdempotencyOptions {
  ttlSeconds: number;
  keyPrefix: string;
}

export class IdempotencyMiddleware {
  constructor(
    private redisClient: RedisClientType,
    private options: IdempotencyOptions = { ttlSeconds: 3600, keyPrefix: 'idempotency:' }
  ) {}

  async handle(req: Request, res: Response, next: NextFunction): Promise<void> {
    try {
      // Only apply to mutating HTTP methods
      if (!['POST', 'PUT', 'PATCH', 'DELETE'].includes(req.method)) {
        return next();
      }

      const idempotencyKey = req.headers['idempotency-key'] as string;

      if (!idempotencyKey) {
        // Generate a key for internal use if not provided
        req.idempotencyKey = uuidv4();
        return next();
      }

      const cacheKey = `${this.options.keyPrefix}${idempotencyKey}`;

      // Check if we have a cached response for this key
      const cachedResponse = await this.redisClient.get(cacheKey);

      if (cachedResponse) {
        const parsedResponse = JSON.parse(cachedResponse);
        res.status(parsedResponse.status).json(parsedResponse.body);
        return;
      }

      // Store the key for this request to prevent concurrent processing
      const lockAcquired = await this.redisClient.set(
        `${cacheKey}:lock`,
        'locked',
        { NX: true, EX: 30 } // 30 second lock
      );

      if (!lockAcquired) {
        // Another request with same key is being processed
        res.status(425).json({ error: 'Request is being processed' });
        return;
      }

      req.idempotencyKey = idempotencyKey;
      next();
    } catch (error) {
      console.error('Idempotency middleware error:', error);
      next(); // Continue without idempotency if Redis fails
    }
  }

  async cacheResponse(idempotencyKey: string, status: number, body: any): Promise<void> {
    if (!idempotencyKey) return;

    const cacheKey = `${this.options.keyPrefix}${idempotencyKey}`;
    const response = { status, body };

    await this.redisClient.setEx(
      cacheKey,
      this.options.ttlSeconds,
      JSON.stringify(response)
    );

    // Release the lock
    await this.redisClient.del(`${cacheKey}:lock`);
  }
}

