// agent-core/src/middleware/reliability.ts
import { Request, Response, NextFunction } from 'express';
import CircuitBreaker from 'opossum';
import { logger } from '../utils/logger';

interface ReliabilityConfig {
  circuitBreaker: {
    timeout: number;
    errorThresholdPercentage: number;
    resetTimeout: number;
  };
  retry: {
    maxAttempts: number;
    delayMs: number;
  };
}

export class ReliabilityMiddleware {
  private config: ReliabilityConfig;

  constructor(config: ReliabilityConfig) {
    this.config = config;
  }

  // Circuit breaker for external services
  public createCircuitBreaker(fn: Function, name: string): CircuitBreaker {
    const breaker = new CircuitBreaker(fn, {
      timeout: this.config.circuitBreaker.timeout,
      errorThresholdPercentage: this.config.circuitBreaker.errorThresholdPercentage,
      resetTimeout: this.config.circuitBreaker.resetTimeout,
    });

    breaker.on('open', () => {
      logger.warn(`Circuit breaker opened for ${name}`);
    });

    breaker.on('close', () => {
      logger.info(`Circuit breaker closed for ${name}`);
    });

    breaker.on('halfOpen', () => {
      logger.info(`Circuit breaker half-open for ${name}`);
    });

    return breaker;
  }

  // Retry mechanism with exponential backoff
  public async retryWithBackoff<T>(
    operation: () => Promise<T>,
    context: string
  ): Promise<T> {
    let lastError: Error | undefined;

    for (let i = 0; i < this.config.retry.maxAttempts; i++) {
      try {
        return await operation();
      } catch (error) {
        lastError = error as Error;
        logger.warn(`Attempt ${i + 1} failed for ${context}: ${error}`);

        if (i < this.config.retry.maxAttempts - 1) {
          // Exponential backoff with jitter
          const delay = Math.min(
            this.config.retry.delayMs * Math.pow(2, i),
            10000 // Max 10 seconds
          ) + Math.floor(Math.random() * 100);

          await new Promise(resolve => setTimeout(resolve, delay));
        }
      }
    }

    logger.error(`All retry attempts failed for ${context}`, lastError);
    throw lastError;
  }

  // Timeout wrapper for operations
  public async withTimeout<T>(
    operation: () => Promise<T>,
    timeoutMs: number,
    context: string
  ): Promise<T> {
    return Promise.race([
      operation(),
      new Promise<never>((_, reject) => 
        setTimeout(() => reject(new Error(`Operation timed out: ${context}`)), timeoutMs)
      )
    ]);
  }
}
