import { Request, Response, NextFunction } from 'express';
import { IdempotencyStore } from './idempotency.store';

export class IdempotencyMiddleware {
  constructor(private store: IdempotencyStore) {}

  async handle(req: Request, res: Response, next: NextFunction) {
    const idempotencyKey = req.headers['idempotency-key'];

    // Only apply to mutating operations
    if (!['POST', 'PUT', 'PATCH', 'DELETE'].includes(req.method)) {
      return next();
    }

    if (!idempotencyKey) {
      return res.status(400).json({
        error: 'Idempotency-Key header is required for this operation'
      });
    }

    try {
      // Check if we have a cached response for this key
      const cachedResponse = await this.store.getResponse(idempotencyKey as string);

      if (cachedResponse) {
        // Return cached response with original status and headers
        res.status(cachedResponse.statusCode);
        Object.entries(cachedResponse.headers).forEach(([key, value]) => {
          res.setHeader(key, value);
        });
        return res.send(cachedResponse.body);
      }

      // Store the request to prevent concurrent processing
      const lockAcquired = await this.store.acquireLock(idempotencyKey as string);
      if (!lockAcquired) {
        return res.status(429).json({
          error: 'Request is already being processed'
        });
      }

      // Attach our storage mechanism to the response
      const originalSend = res.send;
      const originalStatus = res.status;

      let statusCode = 200;
      const headers: Record<string, string> = {};

      res.status = function(code: number) {
        statusCode = code;
        return originalStatus.call(this, code);
      };

      res.send = function(body: any) {
        // Cache the response before sending
        this.store.storeResponse(idempotencyKey as string, {
          statusCode,
          headers,
          body
        }).catch(console.error);

        return originalSend.call(this, body);
      };

      next();
    } catch (error) {
      await this.store.releaseLock(idempotencyKey as string);
      next(error);
    }
  }
}
