interface CachedResponse {
  statusCode: number;
  headers: Record<string, string>;
  body: any;
  timestamp: Date;
}

export class IdempotencyStore {
  private cache: Map<string, CachedResponse> = new Map();
  private locks: Set<string> = new Set();

  async getResponse(key: string): Promise<CachedResponse | null> {
    const cached = this.cache.get(key);

    // Expire entries after 24 hours
    if (cached && (Date.now() - cached.timestamp.getTime()) > 24 * 60 * 60 * 1000) {
      this.cache.delete(key);
      return null;
    }

    return cached || null;
  }

  async storeResponse(key: string, response: Omit<CachedResponse, 'timestamp'>) {
    this.cache.set(key, {
      ...response,
      timestamp: new Date()
    });
    await this.releaseLock(key);
  }

  async acquireLock(key: string): Promise<boolean> {
    if (this.locks.has(key)) {
      return false;
    }

    this.locks.add(key);
    return true;
  }

  async releaseLock(key: string) {
    this.locks.delete(key);
  }
}
