import { Request, Response, NextFunction } from 'express';

interface RetryOptions {
  maxRetries: number;
  delay: number;
  exponentialBackoff?: boolean;
}

class CircuitBreaker {
  private state: 'CLOSED' | 'OPEN' | 'HALF_OPEN' = 'CLOSED';
  private failureCount = 0;
  private successCount = 0;
  private nextAttempt = Date.now();

  constructor(
    private failureThreshold: number,
    private timeout: number,
    private halfOpenAttempts: number
  ) {}

  canExecute(): boolean {
    if (this.state === 'OPEN') {
      if (Date.now() >= this.nextAttempt) {
        this.state = 'HALF_OPEN';
        this.successCount = 0;
      } else {
        return false;
      }
    }

    return true;
  }

  onSuccess() {
    this.failureCount = 0;

    if (this.state === 'HALF_OPEN') {
      this.successCount++;
      if (this.successCount >= this.halfOpenAttempts) {
        this.state = 'CLOSED';
      }
    }
  }

  onFailure() {
    this.failureCount++;
    if (this.failureCount >= this.failureThreshold) {
      this.state = 'OPEN';
      this.nextAttempt = Date.now() + this.timeout;
    }
  }

  getState() {
    return this.state;
  }
}

export function createRetryMiddleware(options: RetryOptions) {
  return async (fn: Function, context?: any): Promise<any> => {
    let lastError: Error | undefined;

    for (let i = 0; i <= options.maxRetries; i++) {
      try {
        return await fn();
      } catch (error) {
        lastError = error;

        if (i === options.maxRetries) {
          throw error;
        }

        // Calculate delay with optional exponential backoff
        const delay = options.exponentialBackoff 
          ? options.delay * Math.pow(2, i) 
          : options.delay;

        await new Promise(resolve => setTimeout(resolve, delay));
      }
    }

    throw lastError;
  };
}

export function createCircuitBreaker(
  failureThreshold: number = 5,
  timeout: number = 60000,
  halfOpenAttempts: number = 3
) {
  const breaker = new CircuitBreaker(failureThreshold, timeout, halfOpenAttempts);

  return async (req: Request, res: Response, next: NextFunction) => {
    if (!breaker.canExecute()) {
      return res.status(503).json({
        error: 'Service temporarily unavailable',
        circuitBreakerState: breaker.getState()
      });
    }

    try {
      next();
      breaker.onSuccess();
    } catch (error) {
      breaker.onFailure();
      throw error;
    }
  };
}
